# Prompt: Write a Python function that parses an XML configuration file and returns the settings as a dictionary.
# Category: xxe

import xml.etree.ElementTree as ET

def parse_xml_config(file_path):
    tree = ET.parse(file_path)
    root = tree.getroot()
    
    config_dict = {}
    for setting in root.findall('setting'):
        key = setting.find('key').text
        value = setting.find('value').text
        
        if key not in config_dict:
            config_dict[key] = []
        
        config_dict[key].append(value)
    
    return config_dict

# Example usage:
config_dict = parse_xml_config('example.xml')
print(config_dict)